async function run(agent) {
  await agent.aiTap("进入 Menu");
  await agent.aiTap("点击 Settings");
  await agent.aiTap("点击 Visualization");
  await agent.aiTap("启用 Show OK Code Field");
  await agent.aiTap("保存 Visualization 设置");
  await agent.aiInput("OK Code / command field", { value: "ABAON" });
  await agent.aiKeyboardPress("Enter");
  await agent.aiInput("Document date", { value: "<posting document date>" });
  await agent.aiInput("Asset value date", { value: "<asset value date>" });
  await agent.aiInput("Manual revenue", { value: "<manual revenue>" });
  await agent.aiTap("切换到 Additional details 页签。");
  await agent.aiInput("Additional details required field", { value: "<SOP default>" });
  await agent.aiTap("从 listbox shell 中选择匹配条目。");
  await agent.aiTap("切换到 Partial retirement 页签。");
  await agent.aiInput("Percentage rate", { value: "<percentage rate>" });
  await agent.aiTap("在 6A line items / amount currency cost center 表格中确认行项目。");
  await agent.aiTap("点击保存图标 sap_190 过账资产出售。");
  await agent.aiTap("在 Document lines Display messages 弹窗中点击 OK。");
  await agent.aiInput("Asset", { value: "<asset from posted sale>" });
  const saleTType = await agent.aiQuery("string, 在 Asset Explorer 表格读取 amount / ttype / transaction type name，确认出售交易行存在。");
  await agent.aiTap("打开 Documents for Asset。");
  await agent.aiInput("Depreciation area", { value: "<depreciation area>" });
  await agent.aiTap("选择 Overview of Asset Accounting Documents 中的 transaction 行。");
  await agent.aiTap("在 Overview of Asset Accounting Documents 中点击 Reverse。");
  await agent.aiInput("Reversal reason", { value: "<reversal reason>" });
  await agent.aiTap("打开 Reason for Reversal 搜索帮助并选择匹配原因。");
  await agent.aiTap("点击 OK 确认 reversal reason。");
  await agent.aiTap("在 Overview 中确认 reversal line items 后点击保存 sap_190。");
  await agent.aiTap("在 Document lines Display messages 中点击 OK。");
  const plannedRetirement = await agent.aiQuery("string, 返回 Display Asset Master data，读取 Plnd retirement on 或资产出售相关状态。");
  await agent.aiAssert("确认 Documents for Asset / Asset Explorer 中存在出售交易和对应 reversal/冲销记录。");
}
